      section8Content: "<p>Nous pouvons mettre à jour cette politique de confidentialité de temps en temps.</p>",
      section9Title: "9. Contact",
      section9Content: '<p>Pour toute question, contactez-nous à <a href="mailto:ismetbayramoglu@gmail.com">ismetbayramoglu@gmail.com</a>.</p>'
